@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="chat-container">
    @* ── Left sidebar: channel list ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (channels is not null)
            {
                @foreach (var channel in channels)
                {
                    <li class="channel-item @(channel.Id == selectedChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-description">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="message-area @(threadRootMessage is null ? "expanded" : "")">
        @if (selectedChannel is not null)
        {
            <div class="message-header">
                <h2># @selectedChannel.Name</h2>
                <span class="header-description">@selectedChannel.Description</span>
            </div>

            <div class="message-list" @ref="messageListRef">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (hasMoreMessages)
                {
                    <button class="load-more-btn" @onclick="LoadOlderMessagesAsync">
                        ↑ Load older messages
                    </button>
                }
                @if (messages is not null)
                {
                    @foreach (var msg in messages)
                    {
                        <div class="message-row" @onmouseenter="() => hoveredMessageId = msg.Id"
                             @onmouseleave="() => hoveredMessageId = null">
                            <div class="message-content-wrapper">
                                <div class="message-meta">
                                    <strong class="message-author">@msg.Author</strong>
                                    <span class="message-time">@FormatRelativeTime(msg.SentAt)</span>
                                </div>
                                <div class="message-text">@msg.Content</div>

                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reaction-row">
                                        @foreach (var reaction in msg.Reactions)
                                        {
                                            <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                                                @reaction.Emoji @reaction.Users.Count
                                            </span>
                                        }
                                    </div>
                                }

                                @{ var threadSummary = threadSummaries?.GetValueOrDefault(msg.Id); }
                                @if (threadSummary is not null)
                                {
                                    <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                        💬 @threadSummary.ReplyCount replies
                                        <span class="thread-last-reply">
                                            Last reply @FormatRelativeTime(threadSummary.LastReplyAt)
                                        </span>
                                    </button>
                                }
                            </div>

                            @if (hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">
                                        💬
                                    </button>
                                    <button class="action-btn" title="Add reaction"
                                            @onclick="() => ToggleEmojiPicker(msg.Id)"
                                            @onclick:stopPropagation="true">
                                        😀
                                    </button>
                                </div>
                                @if (emojiPickerMessageId == msg.Id)
                                {
                                    <div class="emoji-picker">
                                        @foreach (var emoji in commonEmojis)
                                        {
                                            <button class="emoji-option"
                                                    @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                @emoji
                                            </button>
                                        }
                                    </div>
                                }
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2"
                          placeholder="Message #@selectedChannel.Name"
                          @bind="newMessageText"
                          @onkeydown="HandleMessageKeyDown" />
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread">✕</button>
            </div>

            <div class="thread-root-quote">
                <strong>@threadRootMessage.Author</strong>
                <span class="message-time">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                <p>@threadRootMessage.Content</p>
            </div>

            <div class="thread-replies" @ref="threadListRef">
                @if (threadMessages is not null)
                {
                    @foreach (var reply in threadMessages)
                    {
                        <div class="message-row thread-reply">
                            <div class="message-meta">
                                <strong class="message-author">@reply.Author</strong>
                                <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-text">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var reaction in reply.Reactions)
                                    {
                                        <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </span>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2"
                          placeholder="Reply in thread…"
                          @bind="newReplyText"
                          @onkeydown="HandleReplyKeyDown" />
                <button class="send-btn" @onclick="SendReplyAsync" disabled="@string.IsNullOrWhiteSpace(newReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    // Data
    private List<Channel>? channels;
    private Channel? selectedChannel;
    private int selectedChannelId;
    private List<Message>? messages;
    private Dictionary<int, ThreadSummary>? threadSummaries;
    private Message? threadRootMessage;
    private List<Message>? threadMessages;

    // UI state
    private string newMessageText = "";
    private string newReplyText = "";
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private bool isLoadingMore;
    private bool hasMoreMessages;
    private int currentSkip;

    // Element references
    private ElementReference messageListRef;
    private ElementReference threadListRef;

    // JS module
    private IJSObjectReference? jsModule;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels?.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat.razor.js");
        }
    }

    // ── Channel selection ──

    private async Task SelectChannelAsync(Channel channel)
    {
        selectedChannel = channel;
        selectedChannelId = channel.Id;
        currentSkip = 0;
        messages = null;
        threadSummaries = null;
        CloseThread();

        var loaded = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count == PageSize;
        currentSkip = loaded.Count;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channels to update unread counts
        channels = await ChatService.GetChannelsAsync();

        await ScrollToBottomAsync();
    }

    // ── Message sending ──

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || selectedChannel is null)
            return;

        var sent = await ChatService.SendMessageAsync(selectedChannel.Id, newMessageText.Trim(), null);
        newMessageText = "";
        messages?.Add(sent);

        await ScrollToBottomAsync();
    }

    private async Task HandleMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ── Load older messages ──

    private async Task LoadOlderMessagesAsync()
    {
        if (isLoadingMore || selectedChannel is null)
            return;

        isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, currentSkip, PageSize);
        isLoadingMore = false;

        if (older.Count > 0)
        {
            messages?.InsertRange(0, older);
            currentSkip += older.Count;
            BuildThreadSummaries();
        }

        hasMoreMessages = older.Count == PageSize;
    }

    // ── Thread ──

    private async Task OpenThreadAsync(Message rootMessage)
    {
        threadRootMessage = rootMessage;
        emojiPickerMessageId = null;

        var allReplies = await ChatService.GetThreadAsync(rootMessage.Id);
        // Exclude the root message itself
        threadMessages = allReplies.Where(m => m.Id != rootMessage.Id).ToList();

        await ScrollThreadToBottomAsync();
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadMessages = null;
        newReplyText = "";
    }

    private async Task SendReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(newReplyText) || selectedChannel is null || threadRootMessage is null)
            return;

        var reply = await ChatService.SendMessageAsync(
            selectedChannel.Id, newReplyText.Trim(), threadRootMessage.Id);
        newReplyText = "";
        threadMessages?.Add(reply);

        // Also add to main message list if not already present
        if (messages?.All(m => m.Id != reply.Id) == true)
        {
            messages.Add(reply);
        }

        BuildThreadSummaries();
        await ScrollThreadToBottomAsync();
    }

    private async Task HandleReplyKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReplyAsync();
        }
    }

    // ── Reactions ──

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        emojiPickerMessageId = null;
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh messages to reflect updated reactions
        if (selectedChannel is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, currentSkip);
            messages = refreshed;
            hasMoreMessages = refreshed.Count == currentSkip;
            BuildThreadSummaries();
        }

        // Also refresh thread if open
        if (threadRootMessage is not null)
        {
            var allReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
            threadMessages = allReplies.Where(m => m.Id != threadRootMessage.Id).ToList();
            // Update root message in case its reactions changed
            var updatedRoot = allReplies.FirstOrDefault(m => m.Id == threadRootMessage.Id);
            if (updatedRoot is not null)
                threadRootMessage = updatedRoot;
        }
    }

    // ── Thread summaries ──

    private void BuildThreadSummaries()
    {
        if (messages is null) return;

        threadSummaries = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .Where(g => messages.Any(m => m.Id == g.Key))
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)));
    }

    // ── Helpers ──

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "…" : description;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 5 => "just now",
            < 60 => $"{(int)diff.TotalSeconds}s ago",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    // ── JS interop ──

    private async Task ScrollToBottomAsync()
    {
        await Task.Yield(); // Let the render complete
        if (jsModule is not null)
        {
            try { await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef); }
            catch (JSException) { }
        }
    }

    private async Task ScrollThreadToBottomAsync()
    {
        await Task.Yield();
        if (jsModule is not null)
        {
            try { await jsModule.InvokeVoidAsync("scrollToBottom", threadListRef); }
            catch (JSException) { }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            try { await jsModule.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }
    }
}

