export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

/* ── Layout ── */

.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    color: #1d1c1d;
}

/* ── Channel Sidebar ── */

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255,255,255,0.1);
}

.sidebar-header h3 {
    margin: 0;
    color: #fff;
    font-size: 1.1rem;
    font-weight: 700;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 6px 16px;
    cursor: pointer;
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 4px;
    border-radius: 6px;
    margin: 0 8px;
    transition: background 0.15s;
    position: relative;
}

.channel-item:hover {
    background: rgba(255,255,255,0.1);
}

.channel-item.active {
    background: #1264a3;
    color: #fff;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    flex: 1;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-description {
    width: 100%;
    font-size: 0.75rem;
    opacity: 0.7;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
    position: absolute;
    right: 10px;
    top: 8px;
}

/* ── Main Message Area ── */

.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
