toolArgs.file_text:
/* ── Layout ── */

.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    color: #1d1c1d;
}

/* ── Channel Sidebar ── */

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255,255,255,0.1);
}

.sidebar-header h3 {
    margin: 0;
    color: #fff;
    font-size: 1.1rem;
    font-weight: 700;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 6px 16px;
    cursor: pointer;
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 4px;
    border-radius: 6px;
    margin: 0 8px;
    transition: background 0.15s;
    position: relative;
}

.channel-item:hover {
    background: rgba(255,255,255,0.1);
}

.channel-item.active {
    background: #1264a3;
    color: #fff;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    flex: 1;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-description {
    width: 100%;
    font-size: 0.75rem;
    opacity: 0.7;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
    position: absolute;
    right: 10px;
    top: 8px;
}

/* ── Main Message Area ── */

.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-right: 1px solid #e1e1e1;
    overflow: hidden;
}

.message-area.expanded {
    width: 80%;
}

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e1e1e1;
    flex-shrink: 0;
}

.message-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.header-description {
    font-size: 0.85rem;
    color: #616061;
    margin-top: 2px;
    display: block;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-indicator {
    text-align: center;
    padding: 8px;
    color: #888;
    font-size: 0.85rem;
}

.load-more-btn {
    display: block;
    margin: 0 auto 12px;
    background: none;
    border: 1px solid #ddd;
    color: #1264a3;
    padding: 6px 14px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.85rem;
}

.load-more-btn:hover {
    background: #f4f4f4;
}

/* ── Messages ── */

.message-row {
    padding: 6px 8px;
    border-radius: 8px;
    position: relative;
    transition: background 0.1s;
}

.message-row:hover {
    background: #f8f8f8;
}

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.75rem;
    color: #9e9e9e;
}

.message-text {
    font-size: 0.93rem;
    line-height: 1.46;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ── Reactions ── */

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background: #f0f0f0;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: default;
}

/* ── Thread link ── */

.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.82rem;
    cursor: pointer;
    padding: 4px 0 0;
    display: flex;
    align-items: center;
    gap: 6px;
}

.thread-link:hover {
    text-decoration: underline;
}

.thread-last-reply {
    color: #9e9e9e;
    font-size: 0.75rem;
}

/* ── Message actions (hover) ── */

.message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    font-size: 1rem;
    line-height: 1;
}

.action-btn:hover {
    background: #f0f0f0;
}

/* ── Emoji picker ── */

.emoji-picker {
    position: absolute;
    top: -8px;
    right: 80px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 4px 6px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    z-index: 20;
}

.emoji-option {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    font-size: 1.2rem;
    line-height: 1;
}

.emoji-option:hover {
    background: #f0f0f0;
}

/* ── Message input ── */

.message-input-area {
    padding: 12px 20px;
    border-top: 1px solid #e1e1e1;
    display: flex;
    gap: 8px;
    align-items: flex-end;
    flex-shrink: 0;
}

.message-input {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    font-size: 0.93rem;
    font-family: inherit;
    outline: none;
}

.message-input:focus {
    border-color: #1264a3;
    box-shadow: 0 0 0 1px #1264a3;
}

.send-btn {
    background: #007a5a;
    color: #fff;
    border: none;
    padding: 8px 18px;
    border-radius: 8px;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background: #006a4e;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* ── No channel selected ── */

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #888;
    font-size: 1.1rem;
}

/* ── Thread Panel ── */

.thread-panel {
    width: 25%;
    min-width: 280px;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-left: 1px solid #e1e1e1;
