    background: #fafafa;
    flex-shrink: 0;
}

.thread-root-quote p {
    margin: 6px 0 0;
    font-size: 0.9rem;
    color: #444;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

.thread-reply {
    padding: 6px 0;
}

